import{_ as t,a as e,b as d,c as n,d as s,e as i}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as p,o as r,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"IP-геолокация и управление пользователями","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/ip-geolocation-and-user-management.md","filePath":"ru-RU/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ru-RU/Other/ip-geolocation-and-user-management.md"};function h(u,a,g,m,b,P){return r(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="ip-геолокация-и-управление-пользователями" tabindex="-1">IP-геолокация и управление пользователями <a class="header-anchor" href="#ip-геолокация-и-управление-пользователями" aria-label="Permalink to &quot;IP-геолокация и управление пользователями&quot;">​</a></h1><p>IP-геолокация превращает IP-адреса в записях загрузок, устройствах входа и похожих журналах в приблизительные локации.</p><p>После настройки админ-панель может понятнее показывать, откуда идут загрузки и доступы. User Management также позволяет блокировать или восстанавливать доступ к загрузке для подозрительных IP-адресов.</p><h2 id="где-это-настраивается" tabindex="-1">Где это настраивается <a class="header-anchor" href="#где-это-настраивается" aria-label="Permalink to &quot;Где это настраивается&quot;">​</a></h2><p>Откройте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+t+`" alt="IP-геолокация" loading="lazy"></p><h2 id="доступные-настроики" tabindex="-1">Доступные настройки <a class="header-anchor" href="#доступные-настроики" aria-label="Permalink to &quot;Доступные настройки&quot;">​</a></h2><p>Новый процесс IP geolocation поддерживает несколько источников, а не зависит от одного map service.</p><table tabindex="0"><thead><tr><th>Настройка</th><th>Назначение</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Выбирает язык отображения: English, Simplified Chinese, Japanese, French и другие.</td></tr><tr><td>MaxMind Account ID</td><td>Account ID MaxMind для MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>License Key MaxMind.</td></tr><tr><td>Tencent Map Key</td><td>Ключ Tencent Location Service. Полезен для китайских адресов и IP материкового Китая.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Поддерживает многоязычную IP-геолокацию.</td></tr></tbody></table><p>Заполняйте только те сервисы, которые нужны. Настраивать каждое поле не обязательно.</p><p>Если ключей нет, ImgBed все равно попробует встроенные бесплатные источники, но стабильность, поддержка языков и точность могут быть ниже, чем у сервиса, который вы настроите сами.</p><h2 id="рекомендуемыи-выбор" tabindex="-1">Рекомендуемый выбор <a class="header-anchor" href="#рекомендуемыи-выбор" aria-label="Permalink to &quot;Рекомендуемый выбор&quot;">​</a></h2><p>Если в основном нужны китайские адреса:</p><ol><li>Установите IP geolocation language как Simplified Chinese.</li><li>Настройте Tencent Map Key.</li><li>При желании добавьте MaxMind или ipapi как fallback sources.</li></ol><p>Если нужны английские или многоязычные адреса:</p><ol><li>Выберите нужный язык.</li><li>Настройте MaxMind Account ID и License Key.</li><li>Добавьте ipapi Key, если нужны более качественные многоязычные результаты.</li></ol><h2 id="настроика-maxmind" tabindex="-1">Настройка MaxMind <a class="header-anchor" href="#настроика-maxmind" aria-label="Permalink to &quot;Настройка MaxMind&quot;">​</a></h2><p>MaxMind требует:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Найдите account ID в dashboard MaxMind и создайте License Key на странице License Keys.</p><p><img src="`+e+'" alt="Настройка MaxMind key" loading="lazy"></p><p>После генерации вставьте Account ID и License Key в ImgBed и сохраните.</p><p>Бесплатный план MaxMind подходит для ежедневного использования, но имеет request limits. Если квота исчерпана, ImgBed продолжит пробовать другие доступные источники.</p><h2 id="настроика-ipapi" tabindex="-1">Настройка ipapi <a class="header-anchor" href="#настроика-ipapi" aria-label="Permalink to &quot;Настройка ipapi&quot;">​</a></h2><p>ipapi использует APILayer API Key.</p><p>Откройте консоль ipapi и скопируйте показанный там API Key.</p><p><img src="'+d+'" alt="Настройка ipapi" loading="lazy"></p><p>Вставьте его в поле <code>ipapi Key</code> в ImgBed и сохраните.</p><p>ipapi поддерживает многоязычную IP-геолокацию и полезен, когда адреса нужно показывать выбранным языком. Его бесплатный план тоже имеет request limits. Если квота закончится, ImgBed продолжит пробовать другие доступные источники.</p><h2 id="настроика-tencent-map-key" tabindex="-1">Настройка Tencent Map Key <a class="header-anchor" href="#настроика-tencent-map-key" aria-label="Permalink to &quot;Настройка Tencent Map Key&quot;">​</a></h2><p>Tencent Map Key полезен для китайских адресов, особенно IP материкового Китая.</p><p>При создании key в Tencent Location Service включите:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>После создания вставьте key в <code>Tencent Map Key</code> и сохраните.</p><p>Если нужна только базовая китайская IP-геолокация, Tencent Map Key достаточно для старта.</p><h2 id="что-проверять-в-user-management" tabindex="-1">Что проверять в User Management <a class="header-anchor" href="#что-проверять-в-user-management" aria-label="Permalink to &quot;Что проверять в User Management&quot;">​</a></h2><p>User Management доступен в верхней части админ-панели.</p><p><img src="'+n+'" alt="User management" loading="lazy"></p><p>User Management показывает активность загрузок по IP:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Описание</th></tr></thead><tbody><tr><td>IP source</td><td>IP-адрес источника загрузки.</td></tr><tr><td>Address</td><td>Приблизительная локация, определенная по IP.</td></tr><tr><td>Total upload size</td><td>Общий размер файлов, загруженных с этого IP.</td></tr><tr><td>Upload count</td><td>Количество загрузок с этого IP.</td></tr><tr><td>Upload allowed</td><td>Включено — загрузки разрешены. Выключено — загрузки заблокированы.</td></tr></tbody></table><p>Нажмите стрелку слева, чтобы развернуть список файлов, загруженных с этого IP.</p><p>В списке файлов показываются имя файла, preview, размер, moderation result, статус файла и время загрузки. Если загрузки выглядят подозрительно, сначала разверните IP, просмотрите файлы, затем решите, блокировать ли дальнейшие загрузки.</p><p>Если IP подозрительный, выключите <code>Upload allowed</code>. Будущие загрузки с этого IP будут заблокированы.</p><h2 id="поиск-сортировка-и-расширенные-фильтры" tabindex="-1">Поиск, сортировка и расширенные фильтры <a class="header-anchor" href="#поиск-сортировка-и-расширенные-фильтры" aria-label="Permalink to &quot;Поиск, сортировка и расширенные фильтры&quot;">​</a></h2><p>Вверху User Management можно искать по IP source или address.</p><p>Сортируйте по времени, upload count или total upload size, чтобы найти недавних загрузчиков, частые загрузки или IP с большим использованием.</p><p>Для более глубокой проверки откройте advanced filters.</p><p><img src="'+s+'" alt="Расширенные фильтры" loading="lazy"></p><p>Advanced filters поддерживают:</p><table tabindex="0"><thead><tr><th>Фильтр</th><th>Использование</th></tr></thead><tbody><tr><td>Time range</td><td>Показать IP, которые загружали файлы за выбранный период.</td></tr><tr><td>Access status</td><td>Фильтр по normal, blocked и похожим состояниям.</td></tr><tr><td>Allow/block list</td><td>Фильтр по allowlist, blocklist или unset.</td></tr><tr><td>File type</td><td>Показать IP, которые загружали images, videos, audio, documents, code или другие файлы.</td></tr><tr><td>File size</td><td>Фильтр по диапазону размера загруженных файлов.</td></tr><tr><td>Age rating</td><td>Фильтр по unset, General, R12+, R16+, R18 и похожим рейтингам.</td></tr><tr><td>File status</td><td>Фильтр по текущему статусу файла для расследования аномалий.</td></tr></tbody></table><p>Нажмите <code>Apply Filters</code>, чтобы применить. <code>Reset</code> возвращает все данные.</p><h2 id="мобильныи-вид" tabindex="-1">Мобильный вид <a class="header-anchor" href="#мобильныи-вид" aria-label="Permalink to &quot;Мобильный вид&quot;">​</a></h2><p>На мобильных устройствах User Management переходит в карточный layout.</p><p><img src="'+i+`" alt="Мобильный User Management" loading="lazy"></p><p>Каждая карточка показывает IP, address, total upload size, upload count и переключатель upload allowed. Управлять пользователями можно без горизонтальной прокрутки таблицы.</p><h2 id="если-локация-выглядит-неверно" tabindex="-1">Если локация выглядит неверно <a class="header-anchor" href="#если-локация-выглядит-неверно" aria-label="Permalink to &quot;Если локация выглядит неверно&quot;">​</a></h2><p>IP-геолокация приблизительная. Это не точный адрес до улицы или дома.</p><p>Если пользователь за proxy, data center, cloud server или cross-border network, показанная локация может отличаться от реальной.</p><p>Используйте функцию, чтобы понимать примерное происхождение, находить аномальные загрузки и помогать с решениями о блокировке. Не воспринимайте ее как точное отслеживание.</p><h2 id="типичные-случаи" tabindex="-1">Типичные случаи <a class="header-anchor" href="#типичные-случаи" aria-label="Permalink to &quot;Типичные случаи&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Случай</th><th>Значение</th></tr></thead><tbody><tr><td>Address пустой</td><td>IP мог еще не определиться или текущий источник временно недоступен.</td></tr><tr><td>Язык address неверный</td><td>Проверьте IP geolocation language и настроен ли источник с поддержкой этого языка.</td></tr><tr><td>Address показывает data center</td><td>Многие proxy, cloud servers и crawlers отображаются как data center или ISP addresses.</td></tr><tr><td>Upload count высокий</td><td>Внимательно проверьте этот IP и при необходимости заблокируйте загрузки.</td></tr><tr><td>Total upload size большой</td><td>Отсортируйте или отфильтруйте, разверните IP и просмотрите конкретные файлы.</td></tr><tr><td>Нужно восстановить после блокировки</td><td>Включите <code>Upload allowed</code> обратно.</td></tr></tbody></table><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Открыть IP Geolocation в Other Settings</span></span>
<span class="line"><span>-&gt; Выбрать IP geolocation language</span></span>
<span class="line"><span>-&gt; При необходимости заполнить MaxMind, Tencent Map или ipapi credentials</span></span>
<span class="line"><span>-&gt; Сохранить настройки</span></span>
<span class="line"><span>-&gt; Открыть User Management</span></span>
<span class="line"><span>-&gt; Просмотреть IP source, address, total upload size и upload count</span></span>
<span class="line"><span>-&gt; Использовать search, sort или advanced filters для поиска аномальных IP</span></span>
<span class="line"><span>-&gt; Разрешить или заблокировать загрузки при необходимости</span></span></code></pre></div>`,64)])])}const M=p(c,[["render",h]]);export{x as __pageData,M as default};
